+// ============================================================================
+// Array - Shared memory array
+// ============================================================================
+
+/// A shared memory array
+pub fn Array(comptime T: type) type {
+    return struct {
+        const Self = @This();
+
+        allocator: std.mem.Allocator,
+        data: []T,
+        mutex: std.Thread.Mutex,
