+// ============================================================================
+// Lock and Synchronization
+// ============================================================================
+
+/// A process-safe lock (reentrant)
+pub const Lock = struct {
+    const Self = @This();
+
+    mutex: std.Thread.Mutex,
+    locked: bool,
+
+    pub fn init() Self {
+        return .{
+            .mutex = .{},
+            .locked = false,
+        };
+    }
+
+    pub fn acquire(self: *Self, block: bool, timeout: ?f64) bool {
+        _ = timeout;
+        if (block) {
+            self.mutex.lock();
+            self.locked = true;
+            return true;
+        } else {
+            if (self.mutex.tryLock()) {
+                self.locked = true;
+                return true;
+            }
+            return false;
+        }
+    }
+
+    pub fn release(self: *Self) void {
+        self.locked = false;
+        self.mutex.unlock();
+    }
+};
+
+/// Reentrant lock
+pub const RLock = struct {
+    const Self = @This();
+
+    mutex: std.Thread.Mutex,
+    owner: ?std.Thread.Id,
+    count: usize,
+
+    pub fn init() Self {
+        return .{
+            .mutex = .{},
+            .owner = null,
+            .count = 0,
+        };
+    }
+
+    pub fn acquire(self: *Self, block: bool, timeout: ?f64) bool {
+        _ = timeout;
+        const tid = std.Thread.getCurrentId();
+
+        if (self.owner == tid) {
+            self.count += 1;
+            return true;
+        }
+
+        if (block) {
+            self.mutex.lock();
+        } else {
+            if (!self.mutex.tryLock()) {
+                return false;
+            }
+        }
+
+        self.owner = tid;
+        self.count = 1;
+        return true;
+    }
+
+    pub fn release(self: *Self) void {
+        if (self.owner != std.Thread.getCurrentId()) {
+            return; // Not owner
+        }
+
+        self.count -= 1;
+        if (self.count == 0) {
+            self.owner = null;
+            self.mutex.unlock();
+        }
+    }
+};
+
+/// Condition variable
+pub const Condition = struct {
+    const Self = @This();
+
+    cond: std.Thread.Condition,
+    lock: *Lock,
+
+    pub fn init(lock: *Lock) Self {
+        return .{
+            .cond = .{},
+            .lock = lock,
+        };
+    }
+
+    pub fn wait(self: *Self, timeout: ?f64) bool {
+        if (timeout) |t| {
+            const ns = @as(u64, @intFromFloat(t * 1_000_000_000));
+            self.cond.timedWait(&self.lock.mutex, ns) catch return false;
+            return true;
+        } else {
+            self.cond.wait(&self.lock.mutex);
+            return true;
+        }
+    }
+
+    pub fn notify(self: *Self) void {
+        self.cond.signal();
+    }
+
+    pub fn notifyAll(self: *Self) void {
+        self.cond.broadcast();
+    }
+};
